import re
from decimal import Decimal, ROUND_HALF_EVEN

class Money:
    def __init__(self, amount, currency):
        # Validate currency: exactly 3 ASCII letters
        if not (isinstance(currency, str) and re.fullmatch(r'[A-Za-z]{3}', currency)):
            raise ValueError(f"Invalid currency code: {currency!r}")
        self.currency = currency.upper()

        # Parse amount into integer cents
        if isinstance(amount, int) and not isinstance(amount, bool):
            self._cents = amount * 100
        elif isinstance(amount, str):
            s = amount.strip()
            # Allow optional sign, digits, and at most 2 decimal places
            if not re.fullmatch(r'[+-]?\d+(\.\d{1,2})?', s):
                raise ValueError(f"Invalid or too-precise amount: {amount!r}")
            d = Decimal(s)
            self._cents = int((d * 100).to_integral_value(rounding=ROUND_HALF_EVEN))
        else:
            raise ValueError(f"amount must be str or int, got {type(amount).__name__!r}")

    @property
    def cents(self):
        return self._cents

    def _make(self, cents):
        """Internal factory that bypasses __init__ parsing."""
        obj = Money.__new__(Money)
        obj.currency = self.currency
        obj._cents = cents
        return obj

    def __add__(self, other):
        if not isinstance(other, Money):
            return NotImplemented
        if self.currency != other.currency:
            raise ValueError(
                f"Cannot add {self.currency} and {other.currency}"
            )
        return self._make(self._cents + other._cents)

    def __sub__(self, other):
        if not isinstance(other, Money):
            return NotImplemented
        if self.currency != other.currency:
            raise ValueError(
                f"Cannot subtract {other.currency} from {self.currency}"
            )
        return self._make(self._cents - other._cents)

    def __mul__(self, k):
        if not isinstance(k, (int, float)) or isinstance(k, bool):
            return NotImplemented
        # Use Decimal for exact rounding with ties-to-even
        exact = Decimal(str(self._cents)) * Decimal(str(k))
        rounded = int(exact.to_integral_value(rounding=ROUND_HALF_EVEN))
        return self._make(rounded)

    def __rmul__(self, k):
        return self.__mul__(k)

    def __eq__(self, other):
        if not isinstance(other, Money):
            return NotImplemented
        return self.currency == other.currency and self._cents == other._cents

    def __repr__(self):
        return str(self)

    def __str__(self):
        sign = '-' if self._cents < 0 else ''
        abs_cents = abs(self._cents)
        whole = abs_cents // 100
        frac = abs_cents % 100
        return f"{self.currency} {sign}{whole}.{frac:02d}"

